function findValidSplit(nums) {
    let n = nums.length;
    let prefix = new Array(n).fill(0);
    let suffix = new Array(n).fill(0);

    prefix[0] = nums[0];
    suffix[n - 1] = nums[n - 1];

    for (let i = 1; i < n; ++i)
        prefix[i] = prefix[i - 1] * nums[i];

    for (let i = n - 2; i >= 0; --i)
        suffix[i] = suffix[i + 1] * nums[i];

    for (let i = 0; i < n - 1; ++i) {
        if (gcd(prefix[i], suffix[i + 1]) === 1)
            return i;
    }

    return -1;
}

function gcd(a, b) {
    return b === 0 ? a : gcd(b, a % b);
}
```


    The main idea of this solution is to use two arrays - prefix (keeps product of all elements from start to current index) and suffix (keeps product of all elements from current index to end). Then, we iterate through both arrays to find the smallest index with coprime values.
1. Create prefix and suffix arrays with initial values.
2. Compute prefix and suffix arrays by multiplying elements in nums.
3. Iterate from 0 to n-2 and check the gcd of the prefix[i] and suffix[i+1] for each element in the arrays.
4. If the gcd of prefix[i] and suffix[i+1] is 1, return the index i as the smallest index with valid coprimes.
5. If no valid index found, return -1.

